INSERT INTO rooms (id, title, description) VALUES
	('8718f425-0ebe-48aa-9127-4541ed29524c', 'Сириус', 'Это флагманский зал нашей студии, названный в честь самой яркой звезды ночного неба. Пространство спроектировано для реализации масштабных коммерческих проектов и амбициозных творческих идей, требующих большого размаха. Высокие потолки и внушительная площадь позволяют выстраивать сложные декорации и работать с крупногабаритным реквизитом. Здесь премиальное оборудование встречается с архитектурным объёмом, создавая идеальные условия для съёмки.'),
	('602109e2-f729-41f3-b93b-2f9a81878ed6', 'Вега', 'Зал Вега — это воплощение чистоты, обилия воздуха и мягкого естественного света. Пространство наполнено атмосферой спокойствия и гармонии, что делает его идеальным местом для эстетичных портретов и нежных контент-съёмок. Интерьер выполнен в светлых тонах с использованием премиальных фактур, которые не перетягивают внимание на себя, а лишь подчёркивают красоту модели. Каждый уголок здесь продуман так, чтобы создавать лаконичные кадры в стиле минимализма.'),
	('f8dca524-e325-4a14-a049-4f0fe73b15f9', 'Лира', 'Лира — это пространство с глубоким характером и уникальной интерьерной душой. Зал создан для художественной фотографии, где главную роль играет игра светотени и богатство материалов. Сочетание глубоких оттенков и характерной мебели придаёт кадрам особую кинематографичность и объем. Это идеальное место для создания глубоких мужских или женских портретов, а также концептуальных съёмок с историей.'),
	('e4ca86f1-7e2c-4de1-8bc1-5078e91f8736', 'Эфир', 'Зал Эфир представляет собой максимально чистое и «невесомое» пространство, настоящий чистый холст для вашего творчества. Центральное место здесь занимает большая белая циклорама, создающая эффект бесконечного пространства без границ. Минималистичный дизайн гарантирует, что в кадре не будет лишнего визуального шума, а всё внимание зрителя будет приковано к объекту съёмки. Это пространство-трансформер, которое легко подстраивается под задачи фэшн-съёмок, каталогов или рекламных кампаний.'),
	('da0840b7-0a95-401d-8e86-aafa7df976c2', 'Нова', 'Нова — это эпицентр креативной энергии и технологичных визуальных экспериментов. Зал спроектирован для тех, кто не боится работать с цветом, динамичным светом и футуристичными образами. Здесь можно смело выходить за рамки классической фотографии, используя возможности современного оборудования для создания неоновых эффектов и сложных световых схем. Интерьер и техническое оснащение зала позволяют создавать контент, который выглядит современно, дерзко и прогрессивно.');
