INSERT INTO photographers (id, name, surname, description, photo_path) VALUES
    (gen_random_uuid(), 'Пётр', 'Чайковский', 'Мастер классического стиля, умеющий передать истинную глубину и драматизм человеческой души в одном кадре. Его работы — это безупречная симфония света и тени, где каждая деталь выверена до совершенства, а результат всегда остаётся вне времени.', '/images/placeholder.png'),
    (gen_random_uuid(), 'Ханс', 'Циммер', 'Фотограф, превращающий любую съёмку в эпический блокбастер мирового масштаба. Он работает со сложным технологичным светом и огромным пространством, создавая кадры с мощным кинематографическим эффектом, которые хочется рассматривать как кадры из кино.', '/images/placeholder.png'),
    (gen_random_uuid(), 'Антонио', 'Вивальди', 'Творец, который чувствует ритм модели так же тонко, как движение смычка по струнам. Его стиль — это невероятная динамика, страсть и молниеносная смена образов, превращающая процесс съёмки в яркий вихрь эмоций, где каждый кадр звучит по-новому.', '/images/placeholder.png'),
    (gen_random_uuid(), 'Рихард', 'Вагнер', 'Если вам нужна монументальность и мощная драма, Рихард — ваш идеальный выбор. Его работы пропитаны тяжёлой эстетикой, контрастным светом и невероятным величием, превращающим обычный портрет в эпическое полотно, наполненное внутренней силой.', '/images/placeholder.png'),
    (gen_random_uuid(), 'Клод', 'Дебюсси', 'Мастер визуального импрессионизма, работающий с воздухом и тончайшими нюансами кадра. Он создаёт мягкие, словно текучие снимки, наполненные мечтательной атмосферой, где границы реальности размываются, уступая место чистому настроению.', '/images/placeholder.png'),
    (gen_random_uuid(), 'Кровосток', '', 'Мастера предельной честности и суровой эстетики, который видит красоту в прямых линиях и отсутствии лишнего пафоса. Группа Кровосток обеспечит вам такой же лаконичный кадр, как цветы в вазе, где за внешней простотой скрывается глубокий смысл и железная уверенность.', '/images/placeholder.png'),
    (gen_random_uuid(), 'Канеки', 'Кен', 'Фотограф с особым взглядом на тёмную эстетику и сложный психологический портрет. Он виртуозно работает с глубокими тенями, скрытыми смыслами и острым контрастом, превращая внутреннюю борьбу и хрупкость момента в захватывающее визуальное искусство.', '/images/placeholder.png');
INSERT INTO equipment (id, title, description, photo_path) VALUES
	('9596154e-ee45-454a-adda-084fca722807', 'Камера', 'Профессиональные полнокадровые камеры — это сердце съёмочного процесса, гарантирующее исключительную детализацию и глубину цвета. Наша техника позволяет работать в самых разных жанрах, обеспечивая уверенность в каждом нажатии кнопки затвора. Высокое разрешение сенсоров сохраняет мельчайшие нюансы картинки, что критически важно для качественной крупноформатной печати.', '/images/placeholder.png'),
	('1251f03a-1851-491f-8071-0fe87547d35d', 'Штатив', 'Профессиональный штатив обеспечивает абсолютную стабильность камеры, что необходимо для ювелирной точности и идеально резких кадров. Прочные материалы и точные механизмы регулировки позволяют надёжно зафиксировать ракурс для работы с длинными выдержками, макросъемки или создания сложных композиций. Это незаменимый инструмент, когда важен каждый миллиметр точности.', '/images/placeholder.png'),
    ('554c0677-d149-4e82-8c56-355c139e6ee1', 'Объектив', 'Парк топовой светосильной оптики с различным фокусным расстоянием даёт возможность реализовать любые творческие задачи — от масштабных интерьеров до крупных портретов. Высококлассные линзы обеспечивают бритвенную резкость в зоне фокуса и мягкое, художественное размытие фона. Наши объективы безупречно передают геометрию и объем, сохраняя естественную пластику кадра без искажений.', '/images/placeholder.png'),
	('e46bd00d-b682-4adc-8320-aabd9ba4f045', 'Софтбокс', 'Этот модификатор является базовым инструментом для создания мягкого, направленного светового потока, который идеально подходит для портретной и предметной съёмки. Специальные рассеиватели деликатно сглаживают переходы между светом и тенью, делая текстуру визуально чище, а блики — аккуратными. Благодаря разным размерам софтбоксов, вы можете полностью контролировать мягкость рисунка в кадре.', '/images/placeholder.png'),
	('554c0677-d149-4e82-8c56-355c139e6ee1', 'Моноблок', 'Студийные моноблоки обеспечивают мощный и стабильный импульс света, позволяя заморозить любое динамичное движение и получить кристально чистую картинку. Быстрая перезарядка и точная цифровая регулировка мощности дают фотографу полный контроль над световой схемой. Это надёжное оборудование, готовое к длительным и интенсивным съёмочным сессиям любой сложности.', '/images/placeholder.png'),
	('60cab21d-31e8-4589-a145-5556172aa439', '6)Стойка для света', 'Устойчивые стойки — это фундамент вашей световой схемы, обеспечивающий безопасность тяжёлого оборудования и свободу творческих манёвров. Надёжные зажимы и продуманная конструкция позволяют надёжно зафиксировать источники света на нужной высоте или под сложным углом. Они легко перемещаются по залу, позволяя оперативно менять освещение и пробовать новые ракурсы в процессе работы.', '/images/placeholder.png'),
    ('554c0677-d149-4e82-8c56-355c139e6ee1', 'Просветный зонт', 'Просветный зонт — это классический инструмент для получения объёмного и мягкого заполняющего света, имитирующего освещение от большого окна. Он создаёт широкий световой поток, который деликатно подсвечивает тени и придаёт кадру естественность. Компактность и быстрота сборки делают его отличным выбором для создания базового освещения как в классическом портрете, так и при групповой съёмке.', '/images/placeholder.png');
