INSERT INTO reserved_equipment (reserved_equipment_id, reservation_id, equipment_id) VALUES
    (gen_random_uuid(), '165b248a-9d78-4fa5-8b26-6151b8ee5e12', '9596154e-ee45-454a-adda-084fca722807'),
